7004 /// If we have a comparison with a non-canonical predicate, if we can update
7005 /// all the users, invert the predicate and adjust all the users.
7006 CmpInst *InstCombinerImpl::canonicalizeICmpPredicate(CmpInst &I) {
7007   // Is the predicate already canonical?
7008   CmpInst::Predicate Pred = I.getPredicate();
7009   if (InstCombiner::isCanonicalPredicate(Pred))
7010     return nullptr;
7011 
7012   // Can all users be adjusted to predicate inversion?
7013   if (!InstCombiner::canFreelyInvertAllUsersOf(&I, /*IgnoredUser=*/nullptr))
7014     return nullptr;
7015 
7016   // Ok, we can canonicalize comparison!
7017   // Let's first invert the comparison's predicate.
7018   I.setPredicate(CmpInst::getInversePredicate(Pred));
7019   I.setName(I.getName() + ".not");
7020 
7021   // And, adapt users.
7022   freelyInvertAllUsersOf(&I);
7023 
7024   return &I;
7025 }
